x_snc_airop_check_definition.check_script:
(function() {
    try {
        var ga = new GlideAggregate("sn_lg_ops_request");
        ga.addAggregate("COUNT");
        ga.query();
        var c = ga.next() ? parseInt(ga.getAggregate("COUNT")) : 0;
        if (c >= 100) {
            return { status: "ready", actualValue: c + " requests", finding: c + " legal requests found. Now Assist LSD has sufficient request volume for AI-assisted legal triage." };
        } else if (c > 0) {
            return { status: "needs_attention", actualValue: c + " requests", finding: c + " legal requests found (target: 100+). Limited volume reduces Now Assist LSD AI accuracy." };
        } else {
            return { status: "value_blocker", actualValue: "0 requests", finding: "No legal requests found. Now Assist LSD requires request data for AI-assisted legal triage." };
        }
    } catch(e) {
        return { status: "needs_validation", actualValue: "Check failed", finding: "Script execution error: " + e.message };
    }
})
